import React, { useState, useRef } from 'react';
import ComparisonTable from '../components/ComparisonTable';

function DistilBERTAnalysisPage({ onNavigateBack }) {
    const [step, setStep] = useState('IDLE');
    const [inputText, setInputText] = useState('');
    const [scanProgress, setScanProgress] = useState(0);
    const audioContextRef = useRef(null);
    const scanSoundIntervalRef = useRef(null);

    // Metrics State
    const [baselineMetrics, setBaselineMetrics] = useState(null);
    const [analysisResult, setAnalysisResult] = useState(null);
    const [optimizationPlan, setOptimizationPlan] = useState(null);
    const [optimizedMetrics, setOptimizedMetrics] = useState(null);

    // Sound Effects
    const playScanSound = () => {
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        }
        const ctx = audioContextRef.current;
        const osc = ctx.createOscillator();
        const gainNode = ctx.createGain();
        osc.connect(gainNode);
        gainNode.connect(ctx.destination);
        const baseFreq = 600 + Math.random() * 300;
        osc.frequency.setValueAtTime(baseFreq, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(baseFreq * 0.7, ctx.currentTime + 0.1);
        osc.type = 'triangle';
        gainNode.gain.setValueAtTime(0.08, ctx.currentTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.1);
        osc.start(ctx.currentTime);
        osc.stop(ctx.currentTime + 0.1);
    };

    const playTransformerSound = () => {
        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
        }
        const ctx = audioContextRef.current;
        const osc = ctx.createOscillator();
        const gainNode = ctx.createGain();
        osc.connect(gainNode);
        gainNode.connect(ctx.destination);
        osc.frequency.setValueAtTime(300, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(800, ctx.currentTime + 0.2);
        osc.type = 'sawtooth';
        gainNode.gain.setValueAtTime(0.06, ctx.currentTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.2);
        osc.start(ctx.currentTime);
        osc.stop(ctx.currentTime + 0.2);
    };

    const startScanSounds = () => {
        playScanSound();
        let counter = 0;
        scanSoundIntervalRef.current = setInterval(() => {
            counter++;
            if (counter % 4 === 0) playTransformerSound();
            else playScanSound();
        }, 150);
    };

    const stopScanSounds = () => {
        if (scanSoundIntervalRef.current) {
            clearInterval(scanSoundIntervalRef.current);
            scanSoundIntervalRef.current = null;
        }
    };

    const startFineTuning = () => {
        if (!inputText.trim()) {
            alert('Please enter sample text for fine-tuning simulation');
            return;
        }

        setStep('SCANNING');
        setScanProgress(0);

        const utterance = new SpeechSynthesisUtterance("Initiating DistilBERT Transformer Scan. Analyzing Self-Attention Layers.");
        utterance.rate = 1.0;
        utterance.pitch = 0.8;
        window.speechSynthesis.speak(utterance);

        startScanSounds();

        let progress = 0;
        const interval = setInterval(() => {
            progress += 1.5;
            setScanProgress(progress);
            if (progress >= 100) {
                clearInterval(interval);
                stopScanSounds();
                calculateBaseline();
            }
        }, 60);
    };

    const calculateBaseline = () => {
        const textLength = inputText.length;
        const baseCO2 = 0.6 + (textLength / 1000) * 0.3;

        const metrics = {
            model: "DistilBERT",
            runtime_minutes: 50,
            co2_kg: parseFloat(baseCO2.toFixed(4)),
            energy_kwh: parseFloat((baseCO2 * 2.2).toFixed(4)),
            epochs: 3,
            batch_size: 64,
            gpu_load: 92,
            transformer_layers: 6,
            attention_heads: 12
        };

        setBaselineMetrics(metrics);
        setStep('SHOW_BASELINE');
    };

    const startAnalysis = () => {
        setStep('ANALYZING');
        setScanProgress(0);

        let progress = 0;
        const interval = setInterval(() => {
            progress += 3;
            setScanProgress(progress);
            if (progress >= 100) clearInterval(interval);
        }, 80);

        setTimeout(() => {
            setAnalysisResult({
                factors: [
                    "High self-attention computation load",
                    "Large batch size increases memory usage",
                    "3 epochs extends transformer processing time",
                    "Full precision (FP32) training detected"
                ]
            });
            setOptimizationPlan({
                suggestions: [
                    "Reduce epochs from 3 → 2 (Early Stopping)",
                    "Reduce batch size from 64 → 32",
                    "Enable Mixed Precision (FP16) training",
                    "Use gradient checkpointing"
                ],
                estimated_reduction_percentage: 45,
                optimized_config: { epochs: 2, batch_size: 32 }
            });
            setStep('SHOW_SUGGESTIONS');
        }, 2500);
    };

    const applyOptimization = () => {
        setStep('OPTIMIZING');
        setScanProgress(0);

        const utterance = new SpeechSynthesisUtterance("Applying optimizations. Re-running DistilBERT with efficient parameters.");
        utterance.rate = 1.0;
        utterance.pitch = 0.8;
        window.speechSynthesis.speak(utterance);

        startScanSounds();

        let progress = 0;
        const interval = setInterval(() => {
            progress += 2;
            setScanProgress(progress);
            if (progress >= 100) {
                clearInterval(interval);
                stopScanSounds();
                completeOptimization();
            }
        }, 50);
    };

    const completeOptimization = () => {
        setOptimizedMetrics({
            ...baselineMetrics,
            runtime_minutes: 25,
            co2_kg: (baselineMetrics.co2_kg * 0.55).toFixed(4),
            energy_kwh: (baselineMetrics.energy_kwh * 0.55).toFixed(4),
            epochs: 2,
            batch_size: 32
        });
        setStep('COMPLETED');
    };

    return (
        <div style={{ background: 'var(--bg-primary)', minHeight: '100vh', padding: '40px', position: 'relative' }}>
            <div className="scanline"></div>

            {/* Header */}
            <header style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '40px' }}>
                <button onClick={onNavigateBack} className="robotic-btn" style={{ padding: '10px 20px', background: 'rgba(0, 210, 255, 0.1)', border: '1px solid var(--robotic-blue)', color: '#fff', cursor: 'pointer' }}>
                    [ BACK_TO_HQ ]
                </button>
                <div style={{ color: 'var(--accent-magenta)', letterSpacing: '2px', fontWeight: 'bold' }}>
                    MODULE: DistilBERT_TRANSFORMER_DIAGNOSTICS
                </div>
            </header>

            {/* --- STEP 1: TEXT INPUT & SCANNING --- */}
            {(step === 'IDLE' || step === 'SCANNING') && (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '40px' }}>
                    {/* Left: Text Input */}
                    <div>
                        <h3 style={{ fontSize: '1.2rem', marginBottom: '20px', color: '#fff' }}>[ 01 ] TEXT_INPUT_BUFFER</h3>
                        <div className="glass-card" style={{ padding: '30px', border: '2px dashed rgba(192, 132, 252, 0.3)', minHeight: '350px' }}>
                            <textarea
                                value={inputText}
                                onChange={(e) => setInputText(e.target.value)}
                                placeholder="Enter sample text for DistilBERT fine-tuning simulation...&#10;&#10;Example: 'Green AI is important for sustainability. Machine learning models consume significant energy during training.'"
                                style={{
                                    width: '100%', height: '200px', background: 'rgba(0,0,0,0.5)', border: '1px solid rgba(192, 132, 252, 0.3)',
                                    borderRadius: '4px', color: '#fff', padding: '15px', fontSize: '1rem', fontFamily: 'monospace', resize: 'none'
                                }}
                            />
                            {step === 'IDLE' && inputText.trim() && (
                                <button onClick={startFineTuning} className="robotic-btn" style={{ marginTop: '20px', padding: '15px 30px', width: '100%', background: 'rgba(192, 132, 252, 0.2)', border: '1px solid var(--accent-magenta)', color: 'var(--accent-magenta)', cursor: 'pointer', fontWeight: 900 }}>
                                    INITIALIZE_BERT_SCAN
                                </button>
                            )}
                            {step === 'SCANNING' && (
                                <div style={{ marginTop: '20px', padding: '15px', background: 'rgba(0,0,0,0.5)', borderRadius: '4px', border: '1px solid var(--accent-magenta)' }}>
                                    <p style={{ color: 'var(--accent-magenta)', marginBottom: '10px' }}>TRANSFORMER LAYER ANALYSIS: {scanProgress.toFixed(0)}%</p>
                                    <div style={{ height: '6px', background: 'rgba(255,255,255,0.1)', borderRadius: '3px' }}>
                                        <div style={{ width: `${scanProgress}%`, height: '100%', background: 'linear-gradient(90deg, #667eea, #f093fb)', borderRadius: '3px' }}></div>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Right: Transformer Visualization */}
                    <div>
                        <h3 style={{ fontSize: '1.2rem', marginBottom: '20px', color: '#fff' }}>[ 02 ] TRANSFORMER_LAYER_LOG</h3>
                        <div className="glass-card" style={{ padding: '20px', minHeight: '350px', fontFamily: 'monospace' }}>
                            {step === 'SCANNING' && (
                                <div style={{ color: 'var(--accent-blue)' }}>
                                    <p style={{ color: scanProgress > 10 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} TOKENIZATION ... {scanProgress > 10 ? 'COMPLETE ✓' : 'PROCESSING'}</p>
                                    <p style={{ color: scanProgress > 25 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} EMBEDDING_LAYER ... {scanProgress > 25 ? 'MAPPED ✓' : scanProgress > 10 ? 'PROCESSING' : 'PENDING'}</p>
                                    <p style={{ color: scanProgress > 40 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} SELF_ATTENTION [L1-L3] ... {scanProgress > 40 ? 'COMPUTED ✓' : scanProgress > 25 ? 'ATTENTION...' : 'PENDING'}</p>
                                    <p style={{ color: scanProgress > 60 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} SELF_ATTENTION [L4-L6] ... {scanProgress > 60 ? 'COMPUTED ✓' : scanProgress > 40 ? 'ATTENTION...' : 'PENDING'}</p>
                                    <p style={{ color: scanProgress > 75 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} FEEDFORWARD_NETWORK ... {scanProgress > 75 ? 'ACTIVATED ✓' : scanProgress > 60 ? 'PROCESSING' : 'PENDING'}</p>
                                    <p style={{ color: scanProgress > 90 ? 'var(--success-green)' : 'var(--accent-blue)' }}>{'>'} OUTPUT_CLASSIFIER ... {scanProgress > 90 ? 'READY ✓' : scanProgress > 75 ? 'BUILDING' : 'PENDING'}</p>
                                    <p style={{ marginTop: '20px', color: 'var(--accent-orange)' }}>{'>'} CO₂ EMISSION CALCULATION: {scanProgress.toFixed(0)}%</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* --- BASELINE RESULTS --- */}
            {(step === 'SHOW_BASELINE' || step === 'SHOW_SUGGESTIONS' || step === 'COMPLETED') && baselineMetrics && (
                <div className="glass-card fade-in" style={{ padding: '30px', marginBottom: '40px', borderLeft: '4px solid var(--accent-magenta)' }}>
                    <h3 style={{ color: '#fff', marginBottom: '20px' }}>📊 DISTILBERT BASELINE EMISSION</h3>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '20px', textAlign: 'center' }}>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>CO₂ Magnitude</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: 'var(--accent-magenta)' }}>{baselineMetrics.co2_kg} kg</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Energy Used</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{baselineMetrics.energy_kwh} kWh</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Transformer Layers</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: 'var(--accent-blue)' }}>{baselineMetrics.transformer_layers}</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Attention Heads</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{baselineMetrics.attention_heads}</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Epochs</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{baselineMetrics.epochs}</div>
                        </div>
                    </div>
                    {step === 'SHOW_BASELINE' && (
                        <div style={{ textAlign: 'center', marginTop: '40px' }}>
                            <button onClick={startAnalysis} className="robotic-btn" style={{ padding: '15px 40px', border: '2px solid var(--robotic-blue)', background: 'transparent', color: 'var(--robotic-blue)', cursor: 'pointer' }}>
                                [ ANALYZE & IDENTIFY ISSUES ]
                            </button>
                        </div>
                    )}
                </div>
            )}

            {/* --- ANALYZING OVERLAY --- */}
            {step === 'ANALYZING' && (
                <div className="glass-card fade-in" style={{ padding: '60px', textAlign: 'center', border: '2px solid var(--robotic-blue)' }}>
                    <div style={{ width: '60px', height: '60px', margin: '0 auto 20px', border: '3px solid var(--robotic-blue)', borderTop: '3px solid transparent', borderRadius: '50%', animation: 'spin 1s linear infinite' }}></div>
                    <h3 style={{ color: 'var(--robotic-blue)' }}>ANALYZING TRANSFORMER LAYERS...</h3>
                    <p style={{ color: 'var(--text-secondary)' }}>Scanning self-attention weights and emission factors...</p>
                </div>
            )}

            {/* --- SUGGESTIONS --- */}
            {(step === 'SHOW_SUGGESTIONS' || step === 'COMPLETED') && analysisResult && optimizationPlan && (
                <div className="fade-in">
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '40px', marginBottom: '40px' }}>
                        <div className="glass-card" style={{ padding: '30px', borderTop: '4px solid var(--warning-yellow)' }}>
                            <h3 style={{ color: 'var(--accent-orange)' }}>🧠 IMPACT ANALYSIS</h3>
                            <ul style={{ listStyle: 'none', padding: 0, marginTop: '20px' }}>
                                {analysisResult.factors.map((f, i) => <li key={i} style={{ marginBottom: '12px', color: '#ffd700' }}>⚠ {f}</li>)}
                            </ul>
                        </div>
                        <div className="glass-card" style={{ padding: '30px', borderTop: '4px solid var(--success-green)' }}>
                            <h3 style={{ color: 'var(--success-green)' }}>💡 OPTIMIZATION STRATEGY</h3>
                            <ul style={{ listStyle: 'none', padding: 0, marginTop: '20px' }}>
                                {optimizationPlan.suggestions.map((s, i) => <li key={i} style={{ marginBottom: '12px', color: '#fff' }}>✓ {s}</li>)}
                            </ul>
                        </div>
                    </div>
                    {step === 'SHOW_SUGGESTIONS' && (
                        <div style={{ textAlign: 'center' }}>
                            <button onClick={applyOptimization} className="robotic-btn" style={{ padding: '20px 50px', fontSize: '1.2rem', background: 'var(--primary-gradient)', border: 'none', color: '#000', cursor: 'pointer', boxShadow: '0 0 30px rgba(0,242,254,0.4)' }}>
                                APPLY OPTIMIZATIONS & RE-RUN
                            </button>
                        </div>
                    )}
                </div>
            )}

            {/* --- OPTIMIZING OVERLAY --- */}
            {step === 'OPTIMIZING' && (
                <div className="glass-card fade-in" style={{ padding: '60px', textAlign: 'center', border: '2px solid var(--success-green)', background: 'rgba(0, 255, 127, 0.05)' }}>
                    <div style={{ width: '60px', height: '60px', margin: '0 auto 20px', border: '3px solid var(--success-green)', borderTop: '3px solid transparent', borderRadius: '50%', animation: 'spin 1s linear infinite' }}></div>
                    <h3 style={{ color: 'var(--success-green)' }}>RE-RUNNING WITH OPTIMIZED PARAMS...</h3>
                    <p style={{ color: 'var(--text-secondary)' }}>DistilBERT: Epochs=2, Batch=32, FP16=Enabled</p>
                    <div style={{ marginTop: '20px', height: '6px', background: 'rgba(255,255,255,0.1)', borderRadius: '3px', width: '300px', margin: '20px auto' }}>
                        <div style={{ width: `${scanProgress}%`, height: '100%', background: 'var(--success-green)', borderRadius: '3px' }}></div>
                    </div>
                </div>
            )}

            {/* --- COMPLETED --- */}
            {step === 'COMPLETED' && optimizedMetrics && (
                <div className="fade-in">
                    <div className="glass-card" style={{ padding: '20px', marginBottom: '40px', background: 'rgba(0, 255, 127, 0.05)', border: '1px solid var(--success-green)' }}>
                        <h2 style={{ color: '#fff' }}>✅ DISTILBERT OPTIMIZATION SUCCESSFUL</h2>
                        <p style={{ color: 'var(--text-secondary)' }}>Model re-calibrated with reduced carbon footprint.</p>
                    </div>
                    <ComparisonTable baseline={baselineMetrics} optimized={optimizedMetrics} />
                    <div style={{ textAlign: 'center', marginTop: '60px' }}>
                        <button onClick={() => window.location.reload()} className="robotic-btn" style={{ padding: '15px 30px', background: 'transparent', border: '1px solid var(--text-muted)', color: 'var(--text-muted)', cursor: 'pointer' }}>
                            [ START_NEW_SESSION ]
                        </button>
                    </div>
                </div>
            )}

            <style>{`
                @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
            `}</style>
        </div>
    );
}

export default DistilBERTAnalysisPage;
